SELECT COUNT(*)
FROM MEMBER
WHERE MEMBER_ID= #{memberId}

SELECT *
FROM MEMBER
WHERE MEMBER_ID  = #{memberId}
	AND MEMBER_PWD = #{memberPwd}
	AND MEMBER_ACTIVE_YN = 'Y'

SELECT MEMBER_ID
FROM MEMBER
WHERE MEMBER_NAME = #{memberName}
  AND PHONE = #{phone}
  AND MEMBER_ACTIVE_YN = 'Y'
